import { generateText, generateObject } from 'ai';
import { vex } from '@vex_dev/sdk';

const vexMiddleware = vex({
  schema: {
    threatIndicators: {
      cveId: 'string',
      verified: 'boolean',
      confidence: 'number'
    }
  },
  validators: [
    {
      type: 'cve_verify',
      async validate(output) {
        const cve = await fetch(`https://services.nvd.nist.gov/rest/json/cves/2.0?keywordSearch=${output.cveId}`);
        return cve.ok;
      }
    }
  ]
});

export async function analyzeThreat(ioc: string) {
  const { text } = await generateText({
    model: 'openai/gpt-4o',
    prompt: `Analyze IOC: ${ioc}`,
    middleware: [vexMiddleware]
  });
  return text;
}

import { streamObject } from 'ai';
import { createVexAgent } from '@vex_dev/sdk';

const securityAgent = createVexAgent({
  tools: {
    isolateEndpoint: {
      description: 'Isolate endpoint (REQUIRES APPROVAL)',
      parameters: { endpointId: 'string' },
      approvalRequired: true
    }
  },
  guards: {
    humanApproval: {
      condition: (toolCall) => toolCall.name === 'isolateEndpoint',
      blockUntil: 'approved'
    }
  }
});

export async function handleIncident(alert: SecurityAlert) {
  const stream = await streamObject({
    model: 'anthropic/claude-3-5-sonnet-20240620',
    schema: securityAgent.schema,
    prompt: `Handle incident: ${JSON.stringify(alert)}`,
    tools: {
      isolateEndpoint: securityAgent.tools.isolateEndpoint
    }
  });

  return stream;
}

import { generateObject } from 'ai';
import { vex } from '@vex_dev/sdk';

const iocExtractor = vex({
  schema: {
    indicators: {
      ips: ['string'],
      domains: ['string'],
      hashes: ['string'],
      classification: 'string[]'
    }
  },
  redactors: {
    pii: {
      patterns: [/\\b(?:10[.]|172[.]1[6-9]|172[.]2[0-9]|172[.]3[01]|192[.]168)[0-9.]+/],
      replacement: '[INTERNAL]'
    }
  }
});

export async function extractIOCs(logs: string[]) {
  const { object } = await generateObject({
    model: 'google/gemini-2.0-flash-exp',
    schema: iocExtractor.schema,
    prompt: `Extract IOCs from logs: ${logs.join('\n')}`,
    middleware: [iocExtractor]
  });

  return object;
}
